// Central source for generating WhatsApp URLs across the app.
// Priority: content.json → site.json → env var → hardcoded fallback

import { resolveContent } from './content-resolver'

const DEFAULT_PHONE = '+595****4567'
const DEFAULT_MESSAGE = 'Hola! Quisiera información sobre productos'

export function getWhatsappPhone(content?: any): string {
  if (process.env.NEXT_PUBLIC_WHATSAPP_NUMBER) return process.env.NEXT_PUBLIC_WHATSAPP_NUMBER

  if (content) {
    const fromContent =
      resolveContent(content, 'business.whatsappPhone', null) ||
      resolveContent(content, 'business.businessNumber', null)
    if (fromContent) return fromContent
  }

  // Site config fallback via dynamic import (avoid circular)
  try {
    const site = require('@/config/site.json')
    if (site.contact?.whatsapp) return site.contact.whatsapp.replace(/[^0-9]/g, '')
  } catch {}

  return DEFAULT_PHONE.replace(/[^0-9]/g, '')
}

export function getWhatsappUrl(content?: any, customMessage?: string): string {
  const phone = getWhatsappPhone(content)
  const message = customMessage
    || (content ? resolveContent(content, 'business.whatsappMessage', DEFAULT_MESSAGE) : DEFAULT_MESSAGE)
  const clean = phone.replace(/[^0-9]/g, '')
  return `https://wa.me/${clean}?text=${encodeURIComponent(message)}`
}

export function getWhatsappShareUrl(productName: string, content?: any): string {
  const message = `Mira este producto de El Viajero: ${productName}`
  return getWhatsappUrl(content, message)
}

export function getWhatsappCartUrl(content?: any): string {
  const message = `Mirá mi carrito de El Viajero`
  return getWhatsappUrl(content, message)
}
