// Local detection, fallback, and cookie management.
// Used by middleware.ts for locale routing and by components for content loading.

export const LOCALE_CONFIG = {
  default: 'es' as const,
  supported: ['es', 'en', 'gn'] as const,
  names: {
    es: 'Español',
    en: 'English',
    gn: 'Guarani',
  } as Record<string, string>,
  flags: {
    es: '🇵🇾',
    en: '🇺🇸',
    gn: '🛡️',
  } as Record<string, string>,
}

export type Locale = (typeof LOCALE_CONFIG.supported)[number]

export function isSupportedLocale(locale: string): locale is Locale {
  return LOCALE_CONFIG.supported.includes(locale as Locale)
}

export function detectLocale(acceptLanguage?: string, cookie?: string): Locale {
  // 1. Cookie wins
  if (cookie && isSupportedLocale(cookie)) return cookie as Locale

  // 2. Accept-Language header
  if (acceptLanguage) {
    for (const part of acceptLanguage.split(',')) {
      const lang = part.split(';')[0]?.trim().split('-')[0]
      if (lang && isSupportedLocale(lang)) return lang as Locale
    }
  }

  // 3. Default
  return LOCALE_CONFIG.default
}

export function getLocalePath(pathname: string, targetLocale: Locale): string {
  // Strip existing locale prefix, then add the target
  for (const locale of LOCALE_CONFIG.supported) {
    if (pathname.startsWith(`/${locale}/`) || pathname === `/${locale}`) {
      const rest = pathname.replace(`/${locale}`, '') || '/'
      return targetLocale === LOCALE_CONFIG.default ? rest : `/${targetLocale}${rest}`
    }
  }
  // No locale prefix
  return targetLocale === LOCALE_CONFIG.default ? pathname : `/${targetLocale}${pathname}`
}
